var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아, 오랜만이야. 실비아. 그간 잘 지냈나?","JPN":"嬢ちゃん、久しぶりだな。元気にしてたか？","ENG":"Ah, long time no talk, Sylvia. How have you been?","TWN":"嗨，好久不見，希爾維亞。你最近好嗎？"},"stage":{"bg":"BLACK","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"반가워, 메이슨 아저씨. 요즘은 월세가 밀리고 그러진 않지?","JPN":"こんにちは、おじさん。最近は家賃をちゃんと払えているの？","ENG":"It's good to hear from you too, Mr. Mason. Are you still struggling to pay rent?","TWN":"嗨，梅森大叔，最近還有在積欠房租嗎？"},"stage":{"bg":"BLACK","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"용병의 삶은 언제나 궁핍한 법이지.","JPN":"傭兵はつねに貧乏なのさ。","ENG":"A mercenary is always low on funds.","TWN":"傭兵的生活就是永遠不知道下一餐在哪裡。"},"stage":{"bg":"BLACK","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그래도 덕분에 입에 풀칠하고 살고는 있거든.","JPN":"でも、おかげさまで何とか食ってはいけてる。","ENG":"But thanks to you, I at least have money for food.","TWN":"不過托你的福，最近還能勉強餬口。"},"stage":{"bg":"BLACK","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"인사는 이쯤하고, 무슨 일인지 본론부터 말해줄래?","JPN":"挨拶はこのくらいにして、用件を教えてくれる？","ENG":"Let's skip the pleasantries and cut to the chase.","TWN":"客套話就說到這裡，我們進入正題吧？"},"stage":{"bg":"BLACK","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"훈련 땡땡이 중이거든. 근육 바보나 카일이 보면 귀찮아진단 말이야.","JPN":"訓練をバックレてきたのよ。筋肉バカやカイルに見つかると面倒くさくなるから。","ENG":"I'm skipping training for this. If that musclebrain or Kyle finds out, it'll be a bother.","TWN":"我現在是翹課中，要是被肌肉傻瓜或凱爾看到會很麻煩。"},"stage":{"bg":"BLACK","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"후후. 본론을 말하기 전에 하나 묻지.","JPN":"ふふ。本題をいう前に一つ聞こう。","ENG":"Haha, but let me ask you one thing before that.","TWN":"呵呵，進入正題之前我要先問你一個問題。"},"stage":{"bg":"BLACK","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"제이크 워커 대령한테 여자 형제가 있었나?","JPN":"ジェイク・ウォーカー大佐に姉妹がいるのか？","ENG":"Does Colonel Jake Walker have a sister?","TWN":"傑克上校有姊姊或妹妹嗎？"},"stage":{"bg":"BLACK","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"근육 바보를 닮은 여자 형제가 있다면 난 미쳐버리고 말 거야.","JPN":"もしあの筋肉バカに似た姉妹がいたら気がおかしくなるわ。","ENG":"If that musclebrain had a sister who looked just like him, I'd go crazy.","TWN":"肌肉傻瓜要是有姊姊或妹妹我會瘋掉吧。"},"stage":{"bg":"BLACK","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그것참 이상하군.","JPN":"それは妙だな。","ENG":"That's strange.","TWN":"那就奇怪了。"},"stage":{"bg":"BLACK","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"분명 델타 세븐 입대를 독려하는 영상인데.","JPN":"デルタセブンへの入隊を促す映像なんだが。","ENG":"This is definitely footage of Delta Seven encouraging people to enlist.","TWN":"我明明在第七三角洲的招募影片中，"},"stage":{"bg":"BLACK","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이건 아무리 봐도 제이크 워커 대령의 여자 형제거든.","JPN":"これはどう見てもジェイク・ウォーカー大佐の姉妹だ。","ENG":"But no matter how I look at it, the girl looks like Colonel Jake Walker's sister.","TWN":"看到傑克上校的姊姊還妹妹說。"},"stage":{"bg":"BLACK","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"여어, 실비아. 이런데 박혀서 뭐 하는 거야?","JPN":"よお、シルビア。こんなところに籠って何してるんだ？","ENG":"Hey, Sylvia. What are you doing hiding in there?","TWN":"喂，希爾維亞，你躲在這裡做什麼？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"혹시 몰래 애인이랑 연락하는 건가?","JPN":"もしかして彼氏に連絡してるのか？","ENG":"Are you secretly contacting your lover?","TWN":"你在偷情嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"누가 이런 땀내 나는 아저씨를 좋아해! 나 같은 미녀한테 미안하지도 않아?!","JPN":"誰があんな汗臭いおじさん好きになるのよ！　私みたいな美女に失礼だと思わないの！？","ENG":"Who would like an old man that reeks of sweat?! Don't you think you should apologize to a beauty like me?!","TWN":"誰會喜歡這種渾身汗臭味的大叔啦！你說這種話對得起我這個美少女嗎？！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"아하~ 그 용병 양반이었군?","JPN":"あは～例の傭兵だったのか。","ENG":"Aha! It's that mercenary fellow, isn't it?","TWN":"哈～原來是傭兵先生喔？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"흥! 그러는 버터맨도 나랑 같은 처지 아냐?","JPN":"ふん！　そういうバターマンも何してるのよ？","ENG":"Hmph! Like you're any different from me, Sleazeball!","TWN":"哼！油膩男，你也是跑出來偷懶的吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"음~ 평범한 훈련은 나에겐 시시해서 말이야. 3종 정도는 돼야 내 상대가 되지 않겠어?","JPN":"うん～普通の訓練は俺には退屈だからな。俺を相手にするには３種くらいにならないと、だろう？","ENG":"Mm... But normal training doesn't cut it out for me now. I think it'll have to be at least a Category 3, no?","TWN":"嗯～普通的訓練對我來說一點意思都沒有，起碼要3類才夠看吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아, 예에. 그러시겠죠.","JPN":"はいはい。そうでしょうね。","ENG":"Yeah, yeah. Whatever.","TWN":"是是是，你說的都對。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"뭐야? 갑자기 그 심각한 표정은?","JPN":"どうした？　急に深刻な顔して。","ENG":"What? Why are you so stern all of a sudden?","TWN":"幹嘛？為何突然一臉正經？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"카일한텐 말 안 할 테니까, 여기서 쉬고 있으라고.","JPN":"カイルには言わないでやるからここで休んでろよ。","ENG":"I won't tell Kyle, so stay here and rest.","TWN":"好啦，我不會跟凱爾告狀，你就在這裡休息吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그게 아니야.","JPN":"そうじゃないの。","ENG":"That's not it at all.","TWN":"我不是怕凱爾。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"메이슨 아저씨가 버터맨한테 여자 형제가 있냐고 물어보더라고.","JPN":"メイソンおじさんがバターマンに姉妹がいるのかって聞いてきたのよ。","ENG":"Mason was asking if you had a sister, Sleazeball.","TWN":"剛剛梅森大叔問我，你有姊姊或妹妹嗎。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"버터맨은 누나나 동생이 없잖아?","JPN":"バターマンはお姉さんも妹もいないよね？","ENG":"But you don't, right?","TWN":"你都沒有吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"미안하지만, 나한테 동생이 있다고 해도 그런 용병이랑 만나는 건 사절이야.","JPN":"悪いけど、もし妹がいたとしてもあんな傭兵と付き合わせるのはごめんだな。","ENG":"I'm sorry, but even if I did, I wouldn't let her date a mercenary like him.","TWN":"不好意思，就算我有姊姊或妹妹，我也不會允許她跟傭兵交往的。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"잠깐, 그런데 내가 너한테 가족 얘기를 했던가?","JPN":"待てよ、俺がシルビアに家族のこと話したことあったっけ？","ENG":"Wait a minute, but have I ever told you about my family?","TWN":"等等，我有跟你說過我家裡的事嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"으, 응? 그건…….","JPN":"う、え？　それは……","ENG":"H-huh? That’s...","TWN":"呃？那個……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"하하, 그렇게 안 봤는데 이 몸의 매력에 반한거야, 실비아?","JPN":"はは、そうだったとはなぁ、俺の魅力にメロメロになったか、シルビア？","ENG":"Hah hah, are you finally falling in love with me, Sylvia?","TWN":"哈哈，希爾維亞，你是不是被我的魅力所吸引啦？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"하하~ 이것 참. 사내 연애는 취향이 아니거든. 미안하게 됐어.","JPN":"いや～参ったな。社内恋愛は好みじゃ無くて。悪いね。","ENG":"Hah hah, this is awkward. I'm not into office romances. Sorry.","TWN":"哈哈～真是的，抱歉，我不喜歡辦公室戀情。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L4_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아이씨! 아니거든! 도대체 날 뭐로 생각하는 거야?!","JPN":"もう！　違うってば！　何を勘違いしてるの！？","ENG":"Oh come on! And you think that I am?!","TWN":"屁啦！我才沒有！你到底把我當成什麼啦？！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"오늘따라 헛소리가 좀 심하네?","JPN":"さっきから変なことばかり言って！","ENG":"What's with all this nonsense today?","TWN":"你今天廢話很多欸！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"버터맨이랑 닮은 여자가 델타 세븐과 관련된 영상을 찍었다고 했어!","JPN":"そうじゃなくて、バターマンに似た女の人がデルタセブンの映像に映っていたのよ！","ENG":"He told me that he saw a girl who looked just like you in a video related to Delta Seven!","TWN":"是傭兵大叔說，有個和你長得很像的女生拍了一支有關第七三角洲的影片！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"분명 델타 세븐의 마크가 찍혀 있으니 사칭일지도 모른다고.","JPN":"はっきりとデルタセブンのマークが映っていたから偽物かもしれないけど。","ENG":"He said it even had the Delta Seven's symbol showing. It could be an impersonation.","TWN":"上面還有第七三角洲的標誌，有可能是偽造的。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"후우……그냥 버터맨도 따라 오는 건 어때?","JPN":"ふう……いっそのことバターマンも一緒に来たら？","ENG":"Ugh... Why don't you just tag along, Sleazeball?","TWN":"呼……我是想，不如你也一起來確認看看？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"메이슨 아저씨가 영상을 보고 싶으면 사무소로 오라고 그랬거든.","JPN":"メイソンおじさんが映像を見たければ事務所に来いって言ったから。","ENG":"Mason said to come by the office if I wanted to see the video in person.","TWN":"梅森大叔說想看影片的話就去事務所找他。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"흠. 재밌는 냄새가 나는군.","JPN":"ふむ。それは興味をそそられるな。","ENG":"Hmm. That sounds interesting.","TWN":"哼，好像很有趣。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"혹시나 하는 말인데, 귀찮은 일이라면 나는 술이나 마시러 갈 거다.","JPN":"だが前もって言っておくが、面倒なことだったら俺は酒でも飲みに行くからな。","ENG":"Just so you know, if anything bothersome happens, I'm just gonna go drink.","TWN":"我話先說在前頭，要是不好玩，我就要去喝酒囉。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그런 건 카일 녀석한테 맡기는 게 더 나을 걸?","JPN":"そういうのはカイルに任せた方がいいと思うぞ？","ENG":"Wouldn't it be better to leave stuff like this to Kyle?","TWN":"不好玩的事要找凱爾才對。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"네에. 네에. 어련하시겠어요.","JPN":"はい、はい。わかっているわ。","ENG":"Yeah, yeah. I'm sure you think that.","TWN":"好好好， 你說的都對。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"하하! 잘 왔어. 친구들. 이렇게 찾아올 줄 알았다니까?","JPN":"はは！　よく来たな。あんたたちが来ると思ってたよ！","ENG":"Haha! My friends, you're here. I knew you'd come by!","TWN":"哈哈！歡迎，朋友們，我就知道你們會來找我。"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이봐, 메이슨 씨.","JPN":"おい、メイソン。","ENG":"Hey, Mr. Mason.","TWN":"喂，梅森。"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"나는 실비아가 재밌는 일을 벌이는 것 같아서 찾아온 것뿐이야.","JPN":"俺はシルビアが面白いことをしていると思って来ただけだ。","ENG":"I'm here to see what kind of fun Sylvia is up to.","TWN":"是希爾維亞說有好玩的事我才來的。"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"뭔지는 몰라도 귀찮은 일이 아니었으면 좋겠는데.","JPN":"何かは知らないが、面倒くさいことはごめんだからな。","ENG":"I'd prefer it not to be anything too annoying.","TWN":"雖然還不清楚，但希望不是什麼麻煩的事才好。"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"어련하시겠어. 대령.","JPN":"わかっている。大佐。","ENG":"Of course, Colonel.","TWN":"上校，你放心吧。"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"보나마나 일이 커지겠다 싶으면 그 꽉 막힌 친구한테 넘길 생각이겠지.","JPN":"大ごとになりそうだったら、あの堅物に任せるつもりだろう。","ENG":"You're probably going to hand it over to your inflexible friend if it gets out of hand.","TWN":"想也知道，萬一是麻煩事，你就會立刻丟包給那位死板的小哥吧。"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이래서 눈치 빠른 용병은 싫다니까.","JPN":"これだから勘のいい傭兵は嫌いだ。","ENG":"Damn mercenary, figuring it out so quickly.","TWN":"所以說我最討厭聰明的傭兵。"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"얼른 영상이나 보여주지? 우리 시간 많은 사람 아니거든?","JPN":"早く映像を見せてよ。私たち暇じゃないからね？","ENG":"Let's see the footage already. We don't have all day.","TWN":"快給我們看那個影片吧？我們可不是整天閒閒沒事的人。"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"자칫하면 군 사칭으로 일이 커질 수도 있어.","JPN":"一歩間違えれば軍を詐称したとして大変なことになるよ。","ENG":"This could become more serious if it involves impersonating a military officer.","TWN":"這很可能會是部隊詐欺事件。"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"실비아 말대로, 시간이 없다는 것엔 동의해.","JPN":"シルビアの言うとおり、時間が無いことには同意する。","ENG":"It's just like Sylvia said, we don't have a lot of time.","TWN":"希爾維亞說的沒錯，我們很忙。"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이대로 있다간 술집들이 꽉 차게 된다고.","JPN":"このままだと酒場が満席になってしまう。","ENG":"All the bars will be full by the time I arrive at this rate.","TWN":"我還要趕著去喝酒呢，等一下酒吧就會變很多人欸。"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"하아. 요즘 녀석들은 참을성이 없다니까.","JPN":"はぁ。最近の子たちはまったく待つことができないんだな。","ENG":"*Sigh.* People these days have no patience at all.","TWN":"哀，最近的年輕人都沒什麼耐性。"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"자, 잘 봐 두도록. 이 스마트 가이가 발굴해낸 델타 세븐의 영상을!","JPN":"ほら、これを見てみろ。このスマートガイが見つけたデルタセブンの映像を！","ENG":"Here, take a good, hard look. This is the footage this Smart Guy found!","TWN":"來，好好欣賞我這個頭腦派發現的第七三角洲影片！"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"THEMA_STORM","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_NULL","text":{"KOREA":"나는 비공식 최강의 카운터이자 델타 세븐의 자랑.","JPN":"俺は非公式最強のカウンターでありデルタセブンの誇り。","ENG":"I am the unofficial top Counter and the pride of Delta Seven.","TWN":"我是非公認的最強制裁者，也是第七三角洲的驕傲。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"THEMA_STORM","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_NULL","text":{"KOREA":"너희들도 안전을 보장받고, 강해지고 싶니?","JPN":"お前たちも安全を保障され、強くなりたいか？","ENG":"Do you want your safety to be guaranteed? Do you want to be stronger?","TWN":"你們也希望生命安全獲得保證，增加自己的實力嗎？"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"THEMA_STORM","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_NULL","text":{"KOREA":"미래의 희망들을 위해, 우리 델타 세븐은 언제나 두 팔을 활짝 벌려 환영하고 있어.","JPN":"未来の希望のため、デルタセブンはいつでも両腕を広げて歓迎している。","ENG":"For the hope of our future, Delta Seven's doors are open to welcome you.","TWN":"你們都是國家未來的希望，我們第七三角洲會永遠張開雙臂歡迎大家加入。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"THEMA_STORM","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_NULL","text":{"KOREA":"더불어, 군에 입대한다면 자랑스러운 <color=#ffd34c>델타 정신</color>을 함양할 수 있지.","JPN":"また、軍に入隊すると誇らしい<color=#ffd34c>デルタ精神</color>を養うことができるだろう。","ENG":"Also, you'll be able to develop your <color=#ffd34c>Delta spirit</color> after enlisting.","TWN":"不只如此，加入部隊後，還可以學習榮耀的<color=#ffd34c>三角洲精神</color>。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"THEMA_STORM","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_NULL","text":{"KOREA":"이는 곧 자신의 자랑이자, 뜨거운 전우애가 피어오르는 일이라고?","JPN":"これは自らにとっての誇りになり、熱い戦友愛を育てられるチャンスだぞ？","ENG":"That will be your pride and joy, along with good comradeship.","TWN":"這會成為你的驕傲，而且還可以體驗炙熱的同袍之愛。"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"THEMA_STORM","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_NULL","text":{"KOREA":"델타 세븐. ","JPN":"デルタセブン。 ","ENG":"Delta Seven.","TWN":"第七三角洲，"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"THEMA_STORM","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_NULL","text":{"KOREA":"<color=#ffd34c>당.장.입.대.해.</color>","JPN":"<color=#ffd34c>す。ぐ。入。隊。せ。よ。</color>","ENG":"<color=#ffd34c>JOIN NOW.</color>","TWN":"<color=#ffd34c>立刻報名加入。</color>"},"stage":{"bg":"COUNTERSIDE_GRAY","bgm":"THEMA_STORM","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"어. 음. 확실히 조작된 영상은 아닌 것 같네.","JPN":"えーと、確かに偽物ではなさそうだね。","ENG":"Uh, well... I'm certain the video isn't faked.","TWN":"呃，這部影片確實不是造假的。"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"후후, 재미있는 영상이군. 그래서?","JPN":"ふふ。面白い映像だな。で？","ENG":"Hah hah, that was an entertaining video. So?","TWN":"呵呵，很有趣的影片，然後呢？"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"응? 이걸 보고도 아무렇지도 않아?","JPN":"え？　これを見て何とも思わないの？","ENG":"Hmm? You're okay with this after seeing it in person?","TWN":"嗯？你看完影片沒有任何感想嗎？"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"분명 화가 머리끝까지 올라서 닥치는대로 튀겨버리겠다고 할 줄 알았는데.","JPN":"完全に頭にきて、すぐにでも飛びかかるかと思ったのに。","ENG":"I was sure you'd be livid and cursing to teach this person a lesson.","TWN":"我還以為你會立刻火冒三丈，然後說見她一次就打一次。"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"응? 내가 왜?","JPN":"うん？　なんで俺が？","ENG":"Hmm? Why would I?","TWN":"嗯？為何？"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"관리국 비공인 탑 카운터, 이 제이크 워커를 따라 하는 여성 팬이 있어도 이상하지는 않지.","JPN":"管理局非公認トップカウンター、このジェイク・ウォーカーを真似したくなる女性ファンがいてもおかしくはないだろう。","ENG":"It's not strange for Jake Walker, the unofficial top Counter, to have female fans, is it?","TWN":"身為管理局非公認頂尖制裁者，有個女粉絲也是正常的吧？"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"오히려 이 몸의 매력을 알아준 것 같아 기분이 좋은걸?","JPN":"むしろ俺の魅力をわかってくれたようで嬉しいけどな？","ENG":"I'm actually flattered that she noticed my charms.","TWN":"她這樣宣傳我的魅力，我倒是很開心呢。"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"여성 팬이라……그럴 가능성도 있겠어.","JPN":"女性ファンか……その可能性もあるな。","ENG":"A female fan, eh...? That's also a possibility.","TWN":"女粉絲嗎……也是不無可能。"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"심지어 눈까지 똑 닮았잖아? 세간에선 이걸 운명이라고 한다지?","JPN":"しかも目もとまでそっくりだっただろ？　世間ではこれを運命というんだよな？","ENG":"Her eyes and mine are strikingly similar. Don't people call this \\"fate\\"?","TWN":"而且連眼睛都很像欸？這就叫作命中注定吧？"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"한 번 만나 보고 싶군.","JPN":"一度会ってみたいな。","ENG":"I'd like to meet her in person.","TWN":"真想親自會會她。"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"하아. 겨우 그런 이유로 보고 싶다는 거야?","JPN":"はぁ。そんな理由で会ってみたいの？","ENG":"*Sigh.* That's your only reason?","TWN":"哈，就因為這個理由？"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"군 사칭이라던가, 군 기강 해이라던가…….","JPN":"軍を詐称してるとか、軍の威厳のためにとか……","ENG":"Nothing about military impersonation or discipline...?","TWN":"你不擔心是部隊詐欺事件，或是軍紀渙散……"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그런 건 저 아가씨를 만나고 나서 생각해도 늦지 않아.","JPN":"それはあのお嬢さんに会ってから考えても遅くはない。","ENG":"It won't be too late to go over all that after talking with her.","TWN":"這些等見到她之後再說也不遲。"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"중요한 건 이 일이 술 마시는 것보다 재밌어 보인다는 거지.","JPN":"大事なのはこの件が酒より面白そうだということだ。","ENG":"What's important right now is that this looks more fun than going out drinking.","TWN":"重點是，這件事似乎比喝酒還有趣。"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이봐, 메이슨 씨! 이 영상을 입수한 곳이 어디지?","JPN":"おい、メイソン！　この映像をどこで入手した？","ENG":"Hey, Mr. Mason! Where'd you find this video?","TWN":"喂，梅森！這影片你從哪弄來的？"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이건 침식 재난이 발생했을 때 우연히 신호에 잡힌 영상이야.","JPN":"今回の侵食災害が発生した時、偶然に信号が捉えた映像だ。","ENG":"I caught the signal by accident when the Corruption Disaster occurred.","TWN":"這是發生侵蝕災難時，訊號湊巧抓到的影片。"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"워낙 순식간에 잡힌 영상이라 나는 비밀 프로젝트라도 발견한 줄 알았다니까.","JPN":"ほんの一瞬の隙に映ったから、俺は秘密プロジェクトでも発見したのかと思ったよ。","ENG":"It was only for a brief second that I thought it was some kind of top-secret project.","TWN":"因為是非常瞬間抓到的影片，我原本還以為是什麼秘密計畫。"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"자, 여기 영상을 입수한 좌표야.","JPN":"ほら、これが映像を入手した座標だ。","ENG":"Here, these are the coordinates of where the footage was found.","TWN":"拿去吧，這就是抓到這支影片的座標。"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L31_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이 좌표는…….","JPN":"この座標は……","ENG":"Those coordinates are...","TWN":"這個座標是……"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"찾아보니 아직도 침식 재난이 수습되지 않은 곳이네.","JPN":"確認してみたけど、未だに侵食災害が発生しているところだね。","ENG":"They are in a place where the Corruption Disaster hasn't been resolved.","TWN":"我查了一下，這個地方的侵蝕災難還沒完全處理完畢。"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이런 데서 전파를 잡아서 뭘 하려고 했던 거야?","JPN":"こんなところで電波を拾って何をしようとしたの？","ENG":"What were you trying to do by sniffing signals from a place like that?","TWN":"你在這種地方收集電波要做什麼？"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"하하! 용병은 항상 살길을 모색해야 해.","JPN":"はは！　傭兵は常に食い扶持を考えねばな。","ENG":"Haha! A mercenary needs to find a way to make a living, right?","TWN":"哈哈！傭兵常常要尋找新的出路。"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"저런 험지에서 얻는 정보가 때로는 일확천금의 기회가 될 수도 있거든.","JPN":"危険地域で得る情報が時には一攫千金のチャンスに繋がることもあるんだ。","ENG":"Information from those hazardous places is sometimes worth a fortune.","TWN":"越危險的地方，收集到的情報就可能越值錢。"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"실비아, 네가 온종일 쓸만한 정보를 찾아 해킹하는 것처럼 말이지.","JPN":"嬢ちゃんが使えそうな情報を探してハッキングしているようにな。","ENG":"It's like how you hack the net all day to find intel, Sylvia.","TWN":"希爾維亞，就像你每天尋找有價值的情報再駭入一樣。"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그건 그냥 정보 수집이거든? 혹시 모를 위험에 대비해서…….","JPN":"あれはただの情報収集だよ？　万が一の危険に備えて……","ENG":"I'm just collecting information! In case any of danger...","TWN":"我那是單純在收集情報好嗎？是預防性的……"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"에휴. 말을 말자. ","JPN":"はあ。まあいいけど。 ","ENG":"Ugh, never mind.","TWN":"算了，跟你解釋這麼多幹嘛。"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그나저나 여기, 관리국에서 수습하고 있는 구역 아니야?","JPN":"ところで、ここは管理局が収拾してるエリアじゃないの？","ENG":"Anyway, isn't that area being restored by the Administration right now?","TWN":"回到正題，這裡不是管理局負責清理的區域嗎？"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"우리 관할이 아닌데 무작정 쳐들어가도 괜찮겠어?","JPN":"私たちの管轄ではないけど、無断で突入してもいいの？","ENG":"It's not our jurisdiction. You sure we can just walk in there?","TWN":"又不是我們的轄區，這樣闖進來沒關係嗎？"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이 스마트 가이를 너무 얕보지 마.","JPN":"このスマートガイを見くびるな。","ENG":"Don't underestimate the smart guy, all right?","TWN":"不准你小看頭腦派。"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"용병은 항상 이럴 때를 대비해 수를 준비해 둔다고.","JPN":"傭兵は常時こんな時のために手を打っておくんだ。","ENG":"A mercenary always has something prepared for times like these.","TWN":"傭兵就是永遠有備案。"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"그래서 기밀 회선으로 나를 불렀다 이 말인가, 메이슨?","JPN":"それで機密回線を使って私を呼んだわけか、メイソン？","ENG":"Is that why you called me using the classified line, Mason?","TWN":"梅森，你現在是用機密電話打給我嗎？"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L1_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그렇지. 자네라면 분명 도와줄 것 같았거든.","JPN":"そう。あんたならきっと手伝ってくれると思ったからな。","ENG":"Exactly. I knew you'd help me out.","TWN":"沒錯，我猜如果是你應該會幫我們吧？"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"자네는 날 오해하고 있는 모양인데.","JPN":"君は私を誤解しているようだが。","ENG":"I think you're misunderstanding something about me.","TWN":"看來你對我有所誤會。"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"정보부 요원은 필요할 때 부르는 택시 같은 게 아니야.","JPN":"情報部のエージェントは便利なタクシーとは違うんだぞ。","ENG":"Intelligence agents aren't taxis you can call whenever you need them.","TWN":"情報部人員不是計程車，可以讓你這樣呼來喚去。"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"위급할 때 쓰라고 열어둔 기밀 회선에 손을 든다고 멈추는 택시가 아니란 말일세.","JPN":"危険時に使う機密回線に連絡すれば、すぐに来るタクシーだと思っては困る。","ENG":"The classified line is meant for emergencies only. We're not your personal cab, okay?","TWN":"這支機密電話是有危險時才能打的，不是你可以這樣亂打的。"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"하지만 재밌는 일……","JPN":"しかし興味深いこと……","ENG":"But if it's something interesting...","TWN":"如果是有趣的事……"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"이 아니라 군 위신의 문제라면 이야기가 다르지.","JPN":"ではなく、軍の威信に関する問題なら話は別だな。","ENG":"I mean, if it's a matter of military prestige, that's another story.","TWN":"也不行，但要是關於軍隊的威望，那就另當別論了。"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"우리는 오랜 협력 관계 아닌가?","JPN":"私たちは長い協力関係にあるからな。","ENG":"We've been working together as partners for a long time, right?","TWN":"畢竟我們一直以來都是互助的關係不是嗎？"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"제이크 대령의 일이라면 특별히 빚을 지우는 것도 나쁘지 않지.","JPN":"ジェイク大佐の案件なら特別借りを作っておくのも悪くはない。","ENG":"And, if it's related to Colonel Jake, I could take advantage of it in the future.","TWN":"若是傑克上校的事，那也不是不能特別通融一次。"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"딱 한 번만일세. 이 일 이후로는 이런 일에 협조해주지 않을 거야.","JPN":"一度だけだぞ。今後このようなことには協力しないからな。","ENG":"I'll allow it just this once. This is the last time I will help you with something like this again.","TWN":"但下不為例，之後我不會再為這種事提供協助。"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"고마워. 택시 기사 양반. 역시 자네라면 들어줄 줄 알았어!","JPN":"ありがとう。運転手さん。あんたなら聞いてくれると思った！","ENG":"Thanks, cab driver. I knew you'd come through!","TWN":"謝謝司機大哥，我就知道你會幫忙！"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"택시 기사가 아니라고!!","JPN":"運転手じゃない！！","ENG":"I told you! I'm not your damn taxi driver!","TWN":"我才不是司機大哥！！"},"stage":{"bg":"OFFICE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};